@import 'tw-animate-css';
@import '@fontsource-variable/geist';

@custom-variant dark (&:is(.dark *));
@custom-variant data-open {
  &:where([data-state='open']),
  &:where([data-open]:not([data-open='false'])) {
    @slot;
  }
}
@custom-variant data-closed {
  &:where([data-state='closed']),
  &:where([data-closed]:not([data-closed='false'])) {
    @slot;
  }
}
@custom-variant data-checked {
  &:where([data-state='checked']),
  &:where([data-checked]:not([data-checked='false'])) {
    @slot;
  }
}
@custom-variant data-unchecked {
  &:where([data-state='unchecked']),
  &:where([data-unchecked]:not([data-unchecked='false'])) {
    @slot;
  }
}
@custom-variant data-disabled {
  &:where([data-disabled='true']),
  &:where([data-disabled]:not([data-disabled='false'])) {
    @slot;
  }
}
@custom-variant data-active {
  &:where([data-state='active']),
  &:where([data-active]:not([data-active='false'])) {
    @slot;
  }
}
@custom-variant data-horizontal {
  &:where([data-orientation='horizontal']) {
    @slot;
  }
}
@custom-variant data-vertical {
  &:where([data-orientation='vertical']) {
    @slot;
  }
}

:root {
  color-scheme: dark;
  --background: #08090b;
  --foreground: #f4f4f5;
  --card: #0d0f12;
  --card-foreground: #fafafa;
  --popover: #0d0f12;
  --popover-foreground: #fafafa;
  --primary: #b9d765;
  --primary-foreground: #101207;
  --secondary: #15171b;
  --secondary-foreground: #fafafa;
  --muted: #15171b;
  --muted-foreground: #a3a7ae;
  --accent: #202328;
  --accent-foreground: #fafafa;
  --destructive: #f85149;
  --border: #262a30;
  --input: #15171b;
  --ring: #b9d765;
  --chart-1: #b9d765;
  --chart-2: #7f9b4a;
  --chart-3: #d1aa24;
  --chart-4: #38b66b;
  --chart-5: #d1aa24;
  --radius: 0rem;
  --radius-control: 0.25rem;
  --radius-item: 0.25rem;
  --radius-overlay: 0.25rem;
  --radius-bar: 0.125rem;
  --sidebar: #08090b;
  --sidebar-foreground: #fafafa;
  --sidebar-primary: #b9d765;
  --sidebar-primary-foreground: #101207;
  --sidebar-accent: #15171b;
  --sidebar-accent-foreground: #fafafa;
  --sidebar-border: #262a30;
  --sidebar-ring: #b9d765;
  --grid-line: rgb(255 255 255 / 0.045);
  --primary-deep: #708936;
  --primary-wash: rgb(185 215 101 / 0.16);
  --success: #38b66b;
  --warning: #d1aa24;
  --link: #d0e891;
  --code: #101216;
  --code-foreground: #e4e7eb;
  --code-highlight: #202328;
  --code-number: #777f8b;
  --selection: rgb(185 215 101 / 0.35);
  --selection-foreground: var(--foreground);
  --header-height: 3.75rem;
}

.dark {
  color-scheme: dark;
}

@theme inline {
  @keyframes accordion-down {
    from {
      height: 0;
    }
    to {
      height: var(--bits-accordion-content-height, var(--accordion-panel-height, auto));
    }
  }
  @keyframes accordion-up {
    from {
      height: var(--bits-accordion-content-height, var(--accordion-panel-height, auto));
    }
    to {
      height: 0;
    }
  }
  @keyframes collapsible-down {
    from {
      height: 0;
      opacity: 0;
    }
    to {
      height: var(--bits-collapsible-content-height, auto);
      opacity: 1;
    }
  }
  @keyframes collapsible-up {
    from {
      height: var(--bits-collapsible-content-height, auto);
      opacity: 1;
    }
    to {
      height: 0;
      opacity: 0;
    }
  }
  --font-sans: 'Geist Variable', sans-serif;
  --font-heading: 'Geist Variable', sans-serif;
  --font-mono:
    ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono', 'Courier New',
    monospace;
  --color-code: var(--code);
  --color-code-foreground: var(--code-foreground);
  --color-code-highlight: var(--code-highlight);
  --color-code-number: var(--code-number);
  --color-selection: var(--selection);
  --color-selection-foreground: var(--selection-foreground);
  --color-grid-line: var(--grid-line);
  --color-primary-deep: var(--primary-deep);
  --color-primary-wash: var(--primary-wash);
  --color-success: var(--success);
  --color-warning: var(--warning);
  --color-link: var(--link);
  --color-sidebar-ring: var(--sidebar-ring);
  --color-sidebar-border: var(--sidebar-border);
  --color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
  --color-sidebar-accent: var(--sidebar-accent);
  --color-sidebar-primary-foreground: var(--sidebar-primary-foreground);
  --color-sidebar-primary: var(--sidebar-primary);
  --color-sidebar-foreground: var(--sidebar-foreground);
  --color-sidebar: var(--sidebar);
  --color-chart-5: var(--chart-5);
  --color-chart-4: var(--chart-4);
  --color-chart-3: var(--chart-3);
  --color-chart-2: var(--chart-2);
  --color-chart-1: var(--chart-1);
  --color-ring: var(--ring);
  --color-input: var(--input);
  --color-border: var(--border);
  --color-destructive: var(--destructive);
  --color-accent-foreground: var(--accent-foreground);
  --color-accent: var(--accent);
  --color-muted-foreground: var(--muted-foreground);
  --color-muted: var(--muted);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-secondary: var(--secondary);
  --color-primary-foreground: var(--primary-foreground);
  --color-primary: var(--primary);
  --color-popover-foreground: var(--popover-foreground);
  --color-popover: var(--popover);
  --color-card-foreground: var(--card-foreground);
  --color-card: var(--card);
  --color-foreground: var(--foreground);
  --color-background: var(--background);
  --radius-sm: calc(var(--radius) * 0.6);
  --radius-md: calc(var(--radius) * 0.8);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) * 1.4);
  --radius-2xl: calc(var(--radius) * 1.8);
  --radius-3xl: calc(var(--radius) * 2.2);
  --radius-4xl: calc(var(--radius) * 2.6);
  --radius-control: var(--radius-control);
  --radius-item: var(--radius-item);
  --radius-overlay: var(--radius-overlay);
  --radius-bar: var(--radius-bar);
}

@layer base {
  * {
    @apply border-border outline-ring/50;
  }
  body {
    @apply bg-background text-foreground;
    font-feature-settings:
      'rlig' 1,
      'calt' 1;
    -webkit-font-smoothing: antialiased;
    text-rendering: geometricPrecision;
  }
  html {
    @apply font-sans;
    background: var(--background);
    scroll-behavior: smooth;
  }
  ::selection {
    background: var(--selection);
    color: var(--selection-foreground);
  }
}

@layer utilities {
  .no-scrollbar {
    -ms-overflow-style: none;
    scrollbar-width: none;
  }

  .no-scrollbar::-webkit-scrollbar {
    display: none;
  }

  .hairline-frame {
    box-shadow:
      0 0 0 1px color-mix(in oklab, var(--color-foreground) 10%, transparent),
      inset 0 1px 0 rgb(255 255 255 / 0.035);
  }

  .focus-ring {
    @apply outline-none focus-visible:border-ring focus-visible:ring-1 focus-visible:ring-ring/50;
  }
}
